import { Router } from "express";
import type { Response } from "express";
import {
  listProducts,
  getProductById,
  adjustProductStock,
} from "../services/productService.js";

const router = Router();

function handleError(err: unknown, res: Response): void {
  if (err instanceof Error && "statusCode" in err) {
    res.status((err as { statusCode: number }).statusCode).json({ error: err.message });
    return;
  }
  res.status(500).json({ error: "Internal server error" });
}

// GET /products - list all products, optionally filter by category
router.get("/products", (req, res) => {
  const { category, minPrice, maxPrice } = req.query;

  const min =
    minPrice && typeof minPrice === "string" && !isNaN(parseFloat(minPrice))
      ? parseFloat(minPrice)
      : undefined;

  const max =
    maxPrice && typeof maxPrice === "string" && !isNaN(parseFloat(maxPrice))
      ? parseFloat(maxPrice)
      : undefined;

  try {
    res.json(
      listProducts(
        category && typeof category === "string" ? category : undefined,
        min,
        max,
      ),
    );
  } catch (err) {
    handleError(err, res);
  }
});

// GET /products/:id
router.get("/products/:id", (req, res) => {
  const id = parseInt(req.params.id, 10);
  try {
    res.json(getProductById(id));
  } catch (err) {
    handleError(err, res);
  }
});

// PATCH /products/:id/stock - update stock
router.patch("/products/:id/stock", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const { adjustment } = req.body as { adjustment: number };

  if (typeof adjustment !== "number") {
    res.status(400).json({ error: "adjustment must be a number" });
    return;
  }

  try {
    res.json(adjustProductStock(id, adjustment));
  } catch (err) {
    handleError(err, res);
  }
});

export { router as productRouter };

