import { Router } from "express";
import type { Response } from "express";
import {
  listOrders,
  getOrderById,
  createOrder,
  updateOrderStatus,
} from "../services/orderService.js";
import type { CreateOrderInput } from "../types.js";

const router = Router();

function handleError(err: unknown, res: Response): void {
  if (err instanceof Error && "statusCode" in err) {
    res.status((err as { statusCode: number }).statusCode).json({ error: err.message });
    return;
  }
  res.status(500).json({ error: "Internal server error" });
}

// GET /orders - list orders, optionally filter by userId or status
router.get("/orders", (req, res) => {
  const { userId, status } = req.query;

  const uid =
    userId && typeof userId === "string" && !isNaN(parseInt(userId, 10))
      ? parseInt(userId, 10)
      : undefined;

  try {
    res.json(
      listOrders(uid, status && typeof status === "string" ? status : undefined),
    );
  } catch (err) {
    handleError(err, res);
  }
});

// GET /orders/:id
